module RefModule(
	input clk,
	input load,
	input [7:0] data_in,
	output [7:0] data_out);logic [7:0] reg_value;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
		if (load) reg_value <= data_in;

	assign data_out = reg_value;

endmodule
